import { nextGeneration } from "./game-of-life.js";

describe("Conway's Game of Life", () => {
  it.todo("should return an empty set when there are no living cells");
  it.todo("should kill a single living cell with no neighbors (underpopulation)");
  it.todo("should kill a living cell with only one neighbor (underpopulation)");
  it.todo("should keep alive a living cell with two live neighbors");
  it.todo("should keep alive a living cell with three live neighbors");
  it.todo("should kill a living cell with four live neighbors (overpopulation)");
  it.todo("should bring a dead cell with exactly three live neighbors to life (reproduction)");
  it.todo("should handle living cells with negative coordinates");
  it.todo("should produce the correct next generation for a blinker pattern (oscillator)");
});

